com.mirth.connect.plugins.javascriptstep.script:
function setMcoInfoInGlobalMap() {
    globalChannelMap.put("mco_code", "AMI");
    globalChannelMap.put("root_sftp_folder", "/lza-prod-esmf");
    globalChannelMap.put("mco_sftp_folder", "mco-amidacare");
  }

  //Deletes the staged Success_/Error_ S3 objects from a prior run of this file before it is reprocessed.
  //Replaces the old d:/mco-success, d:/mco-err local-disk cleanup now that Success Data/Error Data write to S3.
  function deleteStagedS3Files(filename) {
    try {
      var s3 = Packages.com.amazonaws.services.s3.AmazonS3ClientBuilder.standard().withRegion("us-east-1").build();
      var bucket = "txd-sbx-mco-sftp-inbound";
      s3.deleteObject(bucket, "bridgelink-inbound/AMI-success/Success_" + filename);
      s3.deleteObject(bucket, "bridgelink-inbound/AMI-error/Error_" + filename);
      logger.info("Deleted staged S3 success/error objects for " + filename);
    } catch (err) {
      logger.info("Could not delete staged S3 objects for " + filename + ": " + err);
    }
  }

  setMcoInfoInGlobalMap();

  //Indicates the current batch
  var currentBatch = $("batchSequenceId");

  //Get DB information 
  var jdbdcDriver = configurationMap.get("jdbdcDriver");
  var jbdcUrl = configurationMap.get("jbdcUrl");
  var dbName = configurationMap.get("dbName");
  var dbPassword = configurationMap.get("dbPassword");
  var dbConn;

  //Get error codes from configuration map
  var errorCodesString = configurationMap.get("errorCodes");
  //Since config map store it as string, parse it into json
  var errorCodes = JSON.parse(errorCodesString);
  var countyCodes = JSON.parse(configurationMap.get("countyCode"));

  var errorTypesString = configurationMap.get("errorTypes");
  var reprocessMessage = configurationMap.get("reprocessableErrors");
  var errorMessageThrown = JSON.parse(reprocessMessage);
  var errorTypes = JSON.parse(errorTypesString);
  var apiUrl = configurationMap.get("reprocessUrl")

  //Parent try catch block
  try {
    //Establish a connection to the DB
    if (currentBatch == 1) {
      try {
        dbConn = DatabaseConnectionFactory.createDatabaseConnection(
          jdbdcDriver,
          jbdcUrl,
          dbName,
          dbPassword
        );

        var mco_id;
        var mco_name;

        var mcoIdResult = dbConn.executeCachedQuery(
          "select tenant_id, tenant_name from techbd_udi_ingress.tenants where tenant_short_code = ? and is_active='1'",
          [$("mco_code")]
        );
        while (mcoIdResult.next()) {
          mco_id = mcoIdResult.getString(1);
          mco_name = mcoIdResult.getString(2);
        }
        logger.info("Mco name : " + mco_name);
        globalChannelMap.put("mcoId", mco_id);
        globalChannelMap.put("mcoName", mco_name);
      } catch (err) {
        logger.info("Could not establish a connection to database");
        if (dbConn) {
          dbConn.close();
        }
        throw err;
      }
    }

    try {
      //Get the chunk size - used for getting correct row numbers
      var chunkSize = parseInt(configurationMap.get("chunkSize"));

      //Original file name as read from the SFTP
      var filename = $("originalFilename");
      var splittedFileName = filename.split("_");

      //If the filename has '_RS', treat it as a resubmission file
      var isResubmission = filename.indexOf("RS_");

      //If the file is a resubmission, store it in global channel map to use it in the destination level
      if (isResubmission != -1) {
        globalChannelMap.put("isResubmission", true);
      }

      if (filename.toLowerCase().indexOf("FileRejected_".toLowerCase()) != -1) {
        isInvalidFile = true;
        var content = msg.toString().split("\n");
        var errorLine = content[1];
        var errorCode = errorLine.toString().split("|")[3];
        var errorTrace = errorLine.toString().split("|")[4];
        globalChannelMap.put("invalidFileReason", [errorCode]);
        channelMap.put("isLambdaRejection", true);
        channelMap.put("lambdaStackTrace", errorTrace);
      } else {
        var isInvalidFile = false;


        var failedDueToFormat = false;
        var failedDueToConvention = false;

        //If it's not a txt format, fail the file
        if (!filename.includes("txt")) {
          isInvalidFile = true;
          failedDueToFormat = true;
        }
        //If isResubmission is -1, it's a original file
        if (isResubmission == -1) {
          if (splittedFileName && splittedFileName.length != 3) {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
          if (splittedFileName && splittedFileName[0] != $("mco_code")) {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
          if (splittedFileName && splittedFileName[1] != "MDESMF") {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
          if (
            (splittedFileName &&
              splittedFileName[2] &&
              (splittedFileName[2].split("\\.")[0] + "").length != 14) ||
            (
              splittedFileName &&
              splittedFileName[2] &&
              splittedFileName[2].split("\\.").length > 2
            )
          ) {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
        }
        //If it's a resubmission file
        else {
          if (splittedFileName && splittedFileName.length !== 5) {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
          if (splittedFileName && splittedFileName[0] != "RS") {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
          if (splittedFileName && splittedFileName[1] != $("mco_code")) {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
          if (splittedFileName && splittedFileName[2] != "MDESMF") {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
          if (
            splittedFileName &&
            splittedFileName[3] &&
            (splittedFileName[3] + "").length != 14
          ) {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
          if (
            (splittedFileName &&
              splittedFileName[4] &&
              (splittedFileName[4].split("\\.")[0] + "").length != 14) ||
            (
              splittedFileName &&
              splittedFileName[4] &&
              splittedFileName[4].split("\\.").length > 2
            )
          ) {
            isInvalidFile = true;
            failedDueToConvention = true;
          }
        }


        if (failedDueToFormat == true && failedDueToConvention == true) {
          globalChannelMap.put("invalidFileReason", ["EC001", "EC002"]);
        } else if (failedDueToConvention == true) {
          globalChannelMap.put("invalidFileReason", ["EC002"]);
        } else if (failedDueToFormat == true) {
          globalChannelMap.put("invalidFileReason", ["EC001"]);
        }
      }

      var orgFileName = $("originalFilename");
      var splitByFileExtension = orgFileName.split("\\.");
      var destinationFileName = splitByFileExtension[0] + ".txt";
      destinationFileName = destinationFileName.toString();
      channelMap.put("destinationFileName", destinationFileName);
    } catch (err) {
      throw err;
    }

    var shouldSkipAllDestinations = globalChannelMap.get("skipAllDestinations");

    if (shouldSkipAllDestinations == true) {
  var isReprocessable=globalChannelMap.get("isReprocessable");
  if($("batchComplete") == true && isReprocessable == true ){
    logger.info("inside if")
    var jsonData = {
      "fileName": $("originalFilename"),
      "mcoCode": globalChannelMap.get("mco_code")
    };


    // Convert JavaScript object to JSON string
    var jsonString = JSON.stringify(jsonData);

    // Create an HTTP client
    var client = org.apache.http.impl.client.HttpClients.createDefault();

    // Create an HTTP POST request
    var postRequest = new org.apache.http.client.methods.HttpPost(apiUrl);

    // Set the entity with the JSON string (application/json content type)
    var entity = new org.apache.http.entity.StringEntity(jsonString, org.apache.http.entity.ContentType.APPLICATION_JSON);
    postRequest.setEntity(entity);

    // Add the Content-Type header
    postRequest.addHeader("Content-Type", "application/json");
    var isReprocessable =true;


    // Execute the HTTP request and get the response
    new Thread(function () {
      try {
        // Make the API request in a separate thread to prevent blocking the main thread
     logger.info("Waiting before executing reprocess http call");
    Thread.sleep(3000); // Delay in milliseconds (3000 ms = 3 seconds)

    // Make the API request after the delay
    logger.info("executing reprocess http call");
        client.execute(postRequest);
      } catch (apiErr) {
        logger.error("API request failed: " + apiErr.message);
      }
    }).start();
  }
      destinationSet.remove(2); //Remove processed folder file destination
      destinationSet.remove(3); //Remove Db Calls destination
      destinationSet.remove(4); //Remove success data file destination
      destinationSet.remove(5); //Remove Error data file destination
      destinationSet.remove(6); //Remove stream sftp file destination
      destinationSet.remove(7); //Remove rejection receipt file destination since it's already sent
      destinationSet.remove(14); //Remove rejection archive receipt file destination
      destinationSet.remove(16); //Remove file rejection in DB
      destinationSet.remove(8); //Remove success receipt file destination
      destinationSet.remove(13); //Remove success archive receipt file destination
      destinationSet.remove(10); //Remove file rejection alert
      destinationSet.remove(11); //Remove success alert
      destinationSet.remove(12); //Remove file having error alert
    }
    //If the file is invalid and we are on first batch, drop file rejected at the outbound folder and skip all other destinations
    else if (isInvalidFile && currentBatch == 1) {
      destinationSet.remove(2); //Remove processed folder file destination
      destinationSet.remove(3); //Remove Db Calls destination
      destinationSet.remove(4); //Remove success data file destination
      destinationSet.remove(5); //Remove Error data file destination
      destinationSet.remove(6); //Remove stream sftp file destination
      destinationSet.remove(8); //Remove success receipt file destination
      destinationSet.remove(17); //Remove archive success receipt file destination
      destinationSet.remove(11); //Remove success file alert dest
      destinationSet.remove(12); //Remove record errors file alert dest
      channelMap.put(
        "fileRejected",
        true
      );
    }
    //If the file is invalid, but we are at batch higher than 1, skip every destination in order to not process anything
    else if (isInvalidFile && currentBatch != 1) {
      destinationSet.remove(2); //Remove processed folder file destination
      destinationSet.remove(3); //Remove Db Calls destination
      destinationSet.remove(4); //Remove success data file destination
      destinationSet.remove(5); //Remove Error data file destination
      destinationSet.remove(6); //Remove stream sftp file destination
      destinationSet.remove(7); //Remove rejection receipt file destination since it's already sent
      destinationSet.remove(14); //Remove rejection archive receipt file destination
      destinationSet.remove(16); //Remove file rejection in DB
      destinationSet.remove(8); //Remove success receipt file destination
      destinationSet.remove(13); //Remove success archive receipt file destination
      destinationSet.remove(10); //Remove file rejection alert
      destinationSet.remove(11); //Remove success alert
      destinationSet.remove(12); //Remove file having error alert
      channelMap.put(
        "fileRejected",
        true
      );
    }
    //IF it's a valid file, start processing the data
    else {
      channelMap.put("fileRejected", false);
      var lines = msg.toString().split("\n");
      //Remove last element since it will always be an empty line which gets added by chunk logic
      lines.pop();
      var msgObj = [];
      var errors = {};
      var status = "VALIDATED";
      var header =
            "MBR_ID|MBR_LASTNAME|MBR_FIRSTNAME|MBR_DOB|MBR_ADDR_LINE_1|MBR_CITY|MBR_POSTALCODE|MBR_COUNTY|PLAN_ID|MBR_LOB|MBR_LOB_DESC|MBR_CONT_PLAN_ENROLL_DT|MBR_PROS_DISENROLL_DT|EPOP_HIGHUTILIZER|EPOP_HHENROLLED|EPOP_OTHER|EPOP_PREG_POSTPARTUM|EPOP_UNDER18NUTRITION|EPOP_UNDER18|EPOP_ADULTCJ|CHRONIC_CONDITIONS|UNCONTROLLED_ASTHMA|NUTRITION_THERAPY|HEATILLNESS_ERUC|COLDILLNESS_ERUC|THERMOREG_RISK|HEALTHY_HOMES|NUTRITION_COUNSEL|MTM_ILOS|OPWDD_WAIVER|TBI_WAIVER|NHTD_WAIVER|CHILDRENS_WAIVER|MBR_TELE_NUM_HOME|MBR_TELE_NUM_CELL|MBR_TELE_NUM_OTHER|PCP_NPI_NAME|PCP_NPI|PCP_TELE_NUM|EPOP_IDD".split(
          "|"
        );
      var validData = [];

    var lineOfBusiness = ["Mainstream", "MLTCP", "MAP"];
      var allowedBooleans = ["Y", "N", "U"];
          var planIdvalues = ["00000", "99999"]
      var result;
      var fileSize = null;
      var batch_id = null;
      var batch_details_id = null;
      var resubmitted_count = null;

        channelMap.put("errorHeader", header.join("|"));

      if (currentBatch == 1) {
        var firstLine = lines[0].toString().split("|");
        if (
          firstLine.length <= 1 ||
          firstLine.toString().toLowerCase() != header.toString().toLowerCase()
        ) {
          logger.info("ERROR: Invalid Header");
          channelMap.put("fileRejected", true);
          isAlreadyExistError = true;
          globalChannelMap.put("invalidFileReason", ["EC005"]);
          globalChannelMap.put("isFileAlreadyExist", true);
        } else {
          globalChannelMap.put("isHeaderFound", true);
          lines = lines.slice(1);
        }
      }

      var queryResult;
      var batchIdForThisMonth;
      var statusForThisMonth;
      var createdOnUtcForThisMonth;

      if (currentBatch == 1) {
        try {
          logger.info("Member records : " + lines.toString());
          //Get the lines from raw message
          var trimmedLines = msg.toString().trim().split("\n");
          //Remove the header line using shift 
          trimmedLines.shift();
          //After remvoing header, if the next line itself is EOF, reject the file since there are no records to be processed
          if (trimmedLines && (trimmedLines.length === 0 || trimmedLines[0].toString().toLowerCase().trim().equals("eof"))) {
            globalChannelMap.put("invalidFileReason", ["EC081"]);
            globalChannelMap.put("isFileAlreadyExist", true);
            channelMap.put("fileRejected", true);
            isAlreadyExistError = true;
          }

          if (isResubmission == -1) {
            queryResult = dbConn.executeCachedQuery(
                        "select batch_id, status, created_on_utc from mco_data.mco_records where tenant_id = ? and is_active ='1' ORDER BY batch_id DESC LIMIT 1",
              [mco_id]
            );
            while (queryResult.next()) {
              batchIdForThisMonth = queryResult.getString(1);
              statusForThisMonth = queryResult.getString(2);
              createdOnUtcForThisMonth = queryResult.getString(3);
            }

            if (
              statusForThisMonth != "FULLY_PROCESSED" ||
              statusForThisMonth != "PARTIALLY_PROCESSED"
            ) {
              var createdOnUtcForThisMonth = createdOnUtcForThisMonth + "";
              createdOnUtcForThisMonth = createdOnUtcForThisMonth
                .split(" ")[0]
                .split("-");

              var folderNameFromDB = getFolderName(
                parseInt(createdOnUtcForThisMonth[0]),
                parseInt(createdOnUtcForThisMonth[1]) - 1,
                parseInt(createdOnUtcForThisMonth[2])
              );

              var todayJsDate = new Date();
              var presentMonth = todayJsDate.getMonth(); // returns 0 - 11
              var presentDate = todayJsDate.getDate(); //Return today's date
              var presentYear = new Date().getFullYear(); //Return the year

              var presentFolderName = getFolderName(presentYear, presentMonth, presentDate);

              var allowMultipleFiles = configurationMap.get("allowMultipleFiles");

              if (folderNameFromDB == presentFolderName) {
                if (allowMultipleFiles.equals("false")) {
                  globalChannelMap.put("invalidFileReason", ["EC082"]);
                  globalChannelMap.put("isFileAlreadyExist", true);
                  channelMap.put("fileRejected", true);
                  isAlreadyExistError = true;
                }
              }
            }
          }
        } catch (err) {
          throw err;
        }
      }

      var fileName = $("originalFilename");
      //If the filename has '_RS', treat it as a resubmission file
      var isResubmission = fileName.indexOf("RS_");

      //If the file is a resubmission, store it in global channel map to use it in the destination level
      if (isResubmission != -1) {
        globalChannelMap.put("isResubmission", true);
      }

      var splittedFileName = fileName.split("_");
      var rootFilename = "";
      if (isResubmission != -1) {
        //Remove first and last parts to remove RS_ and the _Newtimestamp
        for (var part = 1; part < splittedFileName.length - 1; part++) {
          //If we are not at last part, add _ to rebuild the file name
          if (part != splittedFileName.length - 2) {
            rootFilename = rootFilename + splittedFileName[part] + "_";
          }
          //If we are at last part, add .txt to indicate the format
          else {
            rootFilename = rootFilename + splittedFileName[part] + ".txt";
          }
        }
      }
      //If it's not a resubmission, use the original file name to call the DB
      else {
        rootFilename = fileName;
      }
      rootFilename = rootFilename.toString();
      var isAlreadyExistError = false;
      //Get error codes from configuration map
      var errorCodesString = configurationMap.get("errorCodes");
      //Since config map store it as string, parse it into json
      var errorCodes = JSON.parse(errorCodesString);

      channelMap.put("received_time", new Date().toISOString());

      var isResubmissionAlreadyExistError = false;

      if (!globalChannelMap.get("isFileAlreadyExist")) {
        if (currentBatch == 1) {

          var months = ["01", "02", "03", "04", "05", "06", "07", "08", "09", "10", "11", "12"];

          var date = new Date();
          var month = date.getMonth(); // returns 0 - 11
          var date = date.getDate(); //Return today's date
          var year = new Date().getFullYear(); //Return the year

          var startDate = parseInt(configurationMap.get("startDate"));
          var endDate = parseInt(configurationMap.get("endDate"));

          if (startDate >= endDate) {
            if (date >= startDate) {
              if (month != 11) {
                month = month + 1;
              }
              else {
                month = 0;
                year = year + 1;
              }
            }
            else if (date <= endDate) {
              //Do nothing
            }
            else {
              // 	logger.info("Outside window period")
            }
          }

          var reportingMonth = months[month] + '-' + year;
          reportingMonth = reportingMonth.toString()
          globalChannelMap.put("reportingMonth",reportingMonth)

          try {
            //Make DB calls only on the first batch, to check if file already exist or it's a resubmission. 
            if (isResubmission != -1) {
              var resubmissionCheckResult = dbConn.executeCachedQuery(
              "select batch_id from mco_data.mco_record_details where current_file_name = ? and status not in ('FILE_REJECTED', 'MIRTH_INTERNAL_ERROR', 'LAMBDA_INTERNAL_ERROR') and is_active = '1'",
                [fileName]
              );

              while (resubmissionCheckResult.next()) {
                var batchIdForResubmissionFile =
                  resubmissionCheckResult.getString(1);
              }

              if (batchIdForResubmissionFile != null) {
                isResubmissionAlreadyExistError = true;
                logger.info("ERROR: Received an already processed file");
                channelMap.put("fileRejected", true);
                isAlreadyExistError = true;
                globalChannelMap.put("isFileAlreadyExist", true);
                globalChannelMap.put("invalidFileReason", ["EC003"]);
              }
            }

            if (!isResubmissionAlreadyExistError) {
              //Check if the file exists inside the mco_records table
              result = dbConn.executeCachedQuery(
              "select batch_id, resubmitted_count, status, total_records, reporting_month, errored_count from mco_data.mco_records where root_file_name = ? and status not in ('FILE_REJECTED') and is_active = '1'",
                [rootFilename]
              );
              while (result.next()) {
                batch_id = result.getString(1);
                resubmitted_count = result.getString(2);
                var statusFromDb = result.getString(3);
                var totalRecordsFromDb = result.getString(4);
                var reportingMonthFromDb = result.getString(5);
                var erroredCountFromDb = result.getString(6);
              }
              if (erroredCountFromDb) {
                globalChannelMap.put("erroredCountFromDb", erroredCountFromDb);
              }
              //If batch_id is null, the file doesn't exist. Treat it as a new file
              if (batch_id == null) {
              	logger.info("Generated batch_id null stmt = " + batch_id);
                //If the file has RS_ but the original file not found, reject the file
                if (isResubmission != -1) {
                  logger.info("ERROR: Received an already processed file");
                  channelMap.put("fileRejected", true);
                  isAlreadyExistError = true;
                  globalChannelMap.put("isFileAlreadyExist", true);
                  globalChannelMap.put("invalidFileReason", ["EC006"]);
                } else {
                  //Insert initial entries to the mco_records table 
                  batch_insert = dbConn.executeCachedQuery(
                    "insert into mco_data.mco_records(root_file_name, created_on_utc, updated_on_utc, total_records, processed_count, errored_count, is_active, status, tenant_id, file_size_in_kb, resubmitted_count, sent_to_datalake_time, qa_completed_time, sent_to_mco_time, reporting_month) VALUES (?, current_timestamp, current_timestamp, ?, null, null, '1', 'INPROGRESS', ?, ?, ?, null, null, null, ?::varchar) returning batch_id",
                    [fileName, 0, mco_id, 0, 0, reportingMonth]
                  );
                  logger.info("Before batch_insert.next()");

					batch_id = batch_insert.next()
					    ? batch_insert.getLong("batch_id")
					    : null;

					logger.info("After batch_insert.next()");
					logger.info("batch_id = " + batch_id);
                  //Insert initial entries to the mco_record_details table with the batch_id we received from the previous call
                  batch_details_insert = dbConn.executeCachedQuery(
                    "insert into mco_data.mco_record_details(current_file_name, file_size_in_kb, total_records, created_on_utc, updated_on_utc, is_active, status, batch_id, reporting_month, tenant_id) VALUES (?, ?, ?, current_timestamp, current_timestamp, '1', 'INPROGRESS', ?, ?::varchar, ?) returning batch_details_id",
                    [fileName, 0, 0, batch_id, reportingMonth, mco_id]
                  );
                  batch_details_id = batch_details_insert.next()
                    ? batch_details_insert.getInt("batch_details_id")
                    : null;
                }
              } else {
                //If it's not a resubmission file, but the file is already present in the DB, it should be a file level rejection
                if (isResubmission === -1 && (statusFromDb != 'INPROGRESS' && totalRecordsFromDb != 0)) {
                  logger.info("ERROR: Received an already processed file");
                  channelMap.put("fileRejected", true);
                  isAlreadyExistError = true;
                  globalChannelMap.put("isFileAlreadyExist", true);
                  globalChannelMap.put("invalidFileReason", ["EC003"]);
                }
                //If it's not a resubmission file, but the status is inprogress and count is 0. The file might have been errored out due to some technical issues, so clean any processed files
                else if (isResubmission === -1 && (statusFromDb == 'INPROGRESS' && totalRecordsFromDb == 0)) {
                  try {
                    if (currentBatch == 1) {
                      logger.info('Clearing global map');
                      globalChannelMap.clear();
                  reportingMonth = calculateReportingMonth();
                  globalChannelMap.put("reportingMonth", reportingMonth)
                      setMcoInfoInGlobalMap();
                      var isResubmission = fileName.indexOf("RS_");

                      //If the file is a resubmission, store it in global channel map to use it in the destination level
                      if (isResubmission != -1) {
                        globalChannelMap.put("isResubmission", true);
                      }
                      if (mco_id && mco_name) {
                        globalChannelMap.put("mcoId", mco_id);
                        globalChannelMap.put("mcoName", mco_name);
                      }
                    }

                    deleteStagedS3Files(filename);
                    batch_details_query = dbConn.executeCachedQuery(
                      "select batch_details_id from mco_data.mco_record_details where batch_id = ?::bigint and is_active = '1' and status not in ('FILE_REJECTED', 'MIRTH_INTERNAL_ERROR', 'LAMBDA_INTERNAL_ERROR')",
                      [batch_id]
                    );
                    while (batch_details_query.next()) {
                      batch_details_id = batch_details_query.getString(1);
                    }
                  } catch (err) {
                    throw err;
                  }
                }
                //If it's a resubmission file, update the resubmission count for the file in the DB
                else {
                  logger.info(reportingMonthFromDb + " : " + reportingMonth);
                  logger.info(reportingMonthFromDb != reportingMonth);
                  //If it's a resubmission file, but the original file already is fully processed, reject the resubmission file
                  if (isResubmission != -1 && statusFromDb == "FULLY_PROCESSED") {
                    logger.info("ERROR: Received an already processed file");
                    channelMap.put("fileRejected", true);
                    isAlreadyExistError = true;
                    globalChannelMap.put("isFileAlreadyExist", true);
                    globalChannelMap.put("invalidFileReason", ["EC086"]);
                  } else if (
                    isResubmission != -1 &&
                    statusFromDb == "INPROGRESS"
                  ) {
                    logger.info("ERROR: Received an already processed file");
                    channelMap.put("fileRejected", true);
                    isAlreadyExistError = true;
                    globalChannelMap.put("isFileAlreadyExist", true);
                    globalChannelMap.put("invalidFileReason", ["EC006"]);
                  } else if (reportingMonthFromDb != reportingMonth) {
                    logger.info("ERROR: Received an already processed file");
                    channelMap.put("fileRejected", true);
                    isAlreadyExistError = true;
                    globalChannelMap.put("isFileAlreadyExist", true);
                    globalChannelMap.put("invalidFileReason", ["EC087"]);
                  } else {
                    channelMap.put("fileRejected", false);
                    batch_update = dbConn.executeUpdate(
                      "update mco_audit.mco_records set updated_on_utc = current_timestamp, resubmitted_count = ? where batch_id = ?::bigint",
                      [parseInt(resubmitted_count) + 1, batch_id]
                    );

                    //Get batch_details_id
