                      [batch_id]
                    );
                    while (batch_details_query.next()) {
                      batch_details_id_for_update =
                        batch_details_query.getString(1);
                    }

                    //Deactivate old records and insert a new entry
                    if (
                      batch_details_id_for_update != null &&
                      batch_details_id_for_update != ""
                    ) {
                      batch_details_deactivate = dbConn.executeUpdate(
                        "update mco_data.mco_record_details set is_active = '0' where batch_details_id = ?::bigint",
                        [batch_details_id_for_update]
                      );
                    } else {
                      batch_details_deactivate = dbConn.executeUpdate(
                        "update mco_data.mco_record_details set is_active = '0' where batch_id = ?::bigint",
                        [batch_id]
                      );
