                    batch_details_new_entry = dbConn.executeCachedQuery(
                      "insert into mco_data.mco_record_details(current_file_name, file_size_in_kb, total_records, created_on_utc, updated_on_utc, is_active, status, batch_id, reporting_month, tenant_id) VALUES (?, ?, ?, current_timestamp, current_timestamp, '1', 'INPROGRESS', ?::bigint, ?::varchar, ?) returning batch_details_id",
                      [fileName, 0, 0, batch_id, reportingMonth, mco_id]
                    );
                    batch_details_id = batch_details_new_entry.next()
