      } catch (apiErr) {
        logger.error("API request failed: " + apiErr.message);
      }
    }).start();
  }

  // **Throw the error immediately** after triggering the API call
  throw new Error("Error handled by API call. Stopping further processing.");




  // Log the response
  }


  else {
  try {
  if (!dbConn || currentBatch == 1) {
        dbConn = DatabaseConnectionFactory.createDatabaseConnection(
          jdbdcDriver,
          jbdcUrl,
          dbName,
          dbPassword
        );
      }
      //batch_id/mco_id may still be undefined if the original error occurred before either was assigned;
      //binding a JS "undefined" (as opposed to null) as a JDBC param throws its own TypeError and masks the real error
      if (typeof fileName === "undefined") { fileName = $("originalFilename"); }
      if (typeof batch_id === "undefined") { batch_id = null; }
      if (typeof mco_id === "undefined") { mco_id = null; }
      logger.info("============== INSERTING INTO mco_record_details 1 ==============");
	logger.info("batch_id           : " + batch_id);
      //Insert initial entries to the mco_record_details table with the batch_id we received from the previous call
      batch_details_insert = dbConn.executeCachedQuery(
        "insert into mco_data.mco_record_details(current_file_name, file_size_in_kb, total_records, created_on_utc, updated_on_utc, is_active, status, batch_id, reporting_month, tenant_id) VALUES (?, ?, ?, current_timestamp, current_timestamp, '1', 'MIRTH_INTERNAL_ERROR', ?, null, ?) returning batch_details_id",
        [fileName, 0, 0, batch_id, mco_id]
      );
      var new_batch_details_id = batch_details_insert.next()
        ? batch_details_insert.getInt("batch_details_id")
        : null;
      var error_log_insert = dbConn.executeUpdate(
        "insert into mco_data.mco_record_error_logs (batch_id, error_json, created_on_utc, updated_on_utc, batch_details_id, is_active, error_type_id,tenant_id) values (?::bigint, ?::json, current_timestamp, current_timestamp, ?::bigint, '1', ?,?)",
        [
          batch_id,
          JSON.stringify(err),
          new_batch_details_id,
          errorTypes["MIRTH_INTERNAL_ERROR"]["error_type_id"],
          mco_id,
        ]
      );
      throw err;
    } catch (err) {
      logger.info(err);
      throw err;
    } finally {
      globalChannelMap.clear();
      if ($("batchComplete") != true) {
        globalChannelMap.put("skipAllDestinations", true);
      }
      setMcoInfoInGlobalMap();
      if (dbConn) {
        dbConn.close();
  }
      }
    }
  }

  //DOB Validation
  function dateValidCheck(dateString) {
      // Regex to validate the format: YYYYMMDD
    var regex = /^\d{4}\d{2}\d{2}$/;
    var isRegexValid = regex.test(dateString);
      if (!isRegexValid) {
          return false; // Invalid format
      }

      // Extract year, month, and day from the dateString
      var year = parseInt(dateString.substring(0, 4));
      var MM = parseInt(dateString.substring(4, 6));
      var DD = parseInt(dateString.substring(6, 8));

      if (MM < 1 || MM > 12) {
        return false;
      }

      var daysInMonth = [31, 28, 31, 30, 31, 30, 31, 31, 30, 31, 30, 31];

      if (MM === 2) {
          var isLeapYear = (year % 4 === 0 && year % 100 !== 0) || (year % 400 === 0);
          daysInMonth[1] = isLeapYear ? 29 : 28;
      }


      if (DD < 1 || DD > daysInMonth[MM - 1]) {
      return false;
    }

      return true;
  }

  //Number validator
  function numberValidator(input) {
    var numberRegex = /^[0-9]*$/;
    return numberRegex.test(input);
  }

  // future date validation 

  function isFuturePlanDate(date) {
      try {
          logger.info("inside furutedate" + date);
          var futureMonth = date.substring(4, 6);
          var futureYear = date.substring(0, 4);
          var futureDate = date.substring(6, 8)
          var reportingMonth=globalChannelMap.get("reportingMonth")
          var monthOfReporting = reportingMonth.substring(0, 2);
          var yearOfReporting = reportingMonth.substring(3, 7);
          const endDateOfReportingMonth = new Date(yearOfReporting, monthOfReporting, 0);
          var enrollDate = new Date(futureYear, futureMonth - 1, futureDate);
          if (enrollDate > endDateOfReportingMonth) {
              return false;
          }

          return true;
      }
      catch (err) {
          var errorMessagePlan = {}
    errorMessagePlan.code = errorCodes["EC0100"]["code"],
      errorMessagePlan.description = errorCodes["EC0100"]["description"]

        return false;

      }
  }

  function isPastEnrollDate(date) {
      try {
          var pastMonth = date.substring(4, 6);
          var pastYear = date.substring(0, 4);
          var pastDate = date.substring(6, 8)
          var reportingMonth=globalChannelMap.get("reportingMonth")
          var monthOfReporting = reportingMonth.substring(0, 2);
          var yearOfReporting = reportingMonth.substring(3, 7);
          const startDateOfReportingMonth = new Date(yearOfReporting, monthOfReporting - 1, 1);
          var planDate = new Date(pastYear, pastMonth - 1, pastDate);
          if (planDate < startDateOfReportingMonth) {
              return false;
          }

          return true;
      }
      catch (err) {
          var errorMessage = {}
    errorMessage.code = errorCodes["EC0100"]["code"],
      errorMessage.description = errorCodes["EC0100"]["description"]
  return false;  


  }
  }

  function calculateReportingMonth() {
  var startDate = parseInt(configurationMap.get("startDate"));
  var endDate = parseInt(configurationMap.get("endDate"));

  if (startDate >= endDate) {
  if (date >= startDate) {
    if (month != 11) {
      month = month + 1;
    } else {
      month = 0;
      year = year + 1;
    }
  } else if (date <= endDate) {
    //Do nothing
  } else {
    // 	logger.info("Outside window period")
  }
  }

  var reportingMonth = months[month] + "-" + year;
  reportingMonth = reportingMonth.toString();
  return reportingMonth;
  }


  function futureDOB(dobString) {
      try {
          var todayJsDate = new Date(); // e.g., January 20, 2025
          var MM = dobString.substring(4, 6);
          var DD = dobString.substring(6, 8);
          var year = dobString.substring(0, 4);
          var dobDate = new Date(year, MM - 1, DD);
          if (dobDate > todayJsDate) {
              return false;
          }

          return true;

      }
      catch (err) {
          var errorMessage = {};
    errorMessage.code = errorCodes["EC0100"]["code"],
      errorMessage.description = errorCodes["EC0100"]["description"]

      return false;

      }
  }


  //Alphanumberic validator
  function alphanumericValidator(input) {
    var alphanumericRegex = /^[a-zA-Z0-9]+$/;
    return alphanumericRegex.test(input);
  }

  function getFolderName(year, month, date) {
    var months = [
      "Jan",
      "Feb",
      "Mar",
      "Apr",
      "May",
      "Jun",
      "Jul",
      "Aug",
      "Sep",
      "Oct",
      "Nov",
      "Dec",
    ];
    var startDate = parseInt(configurationMap.get("startDate"));
    var endDate = parseInt(configurationMap.get("endDate"));

    if (startDate >= endDate) {
      if (date >= startDate) {
        if (month != 11) {
          month = month + 1;
        }
        else {
          month = 0;
          year = year + 1;
        }
      }
      else if (date <= endDate) {
        //Do nothing
      }
      else {
        // 	logger.info("Outside window period")
      }
    }

    var folderName = months[month] + "-" + year;
    return folderName;
  }

