var maxLines = parseInt(configurationMap.get("chunkSize"));
var i = 0;
var chunk = "";
var line = "";

  globalChannelMap.put("mco_code", "AMI");
  globalChannelMap.put("root_sftp_folder", "/lza-prod-esmf");
  globalChannelMap.put("mco_sftp_folder", "mco-amidacare");

var isEofFound = globalChannelMap.get("eofFound");

if (isEofFound) {
  return null;
} else {
  while ((line = reader.readLine()) != null) {
  if (line == null) {
    return null;
  }
  line = line + "\n";
  chunk += line;
  i++;
  if (i >= maxLines) {
    return chunk;
  }
}

//When while loop is over, return the last chunk or the null value to indicate file is ended
return chunk != "" ? chunk : null;
}

properties.script:
//Get DB information
var jdbdcDriver = configurationMap.get("jdbdcDriver");
var jbdcUrl = configurationMap.get("jbdcUrl");
var dbName = configurationMap.get("dbName");
var dbPassword = configurationMap.get("dbPassword");
var dbConn;

//Get error codes from configuration map
var errorCodesString = configurationMap.get("errorCodes");
//Since config map store it as string, parse it into json
var errorCodes = JSON.parse(errorCodesString);

var errorTypesString = configurationMap.get("errorTypes");
var errorTypes = JSON.parse(errorTypesString);




try {
  //A per-batch value of 0 (e.g. zero errors, or zero successfully-processed rows) is falsy, so the old
  //`if ($(x))` guard skipped globalChannelMap.put(...) entirely on such batches. If that happened on the
  //first batch, the counter was never initialized at all, leaving it "" (not 0) for downstream ?::bigint binds.
  var recordCount = globalChannelMap.get("recordsCount");
  if (recordCount === null || recordCount === undefined) { recordCount = 0; }
  if ($("no_of_records") !== null && $("no_of_records") !== undefined && $("no_of_records") !== "") {
    recordCount += Number($("no_of_records"));
  }
  globalChannelMap.put("recordsCount", recordCount);

  var fileSize = globalChannelMap.get("totalFileSize");
  if (fileSize === null || fileSize === undefined) { fileSize = 0; }
  if ($("file_size") !== null && $("file_size") !== undefined && $("file_size") !== "") {
    fileSize += Number($("file_size"));
  }
  globalChannelMap.put("totalFileSize", fileSize);

  var status = globalChannelMap.get("fileStatus");
  if ($("status")) {
    status = $("status");
    globalChannelMap.put("fileStatus", status);
  }

  var error = globalChannelMap.get("totalErrors");
  if (error === null || error === undefined) { error = 0; }
  if ($("errorCount") !== null && $("errorCount") !== undefined && $("errorCount") !== "") {
    error += Number($("errorCount"));
  }
  globalChannelMap.put("totalErrors", error);

  var process = globalChannelMap.get("totalProcess");
  if (process === null || process === undefined) { process = 0; }
  if ($("processedCount") !== null && $("processedCount") !== undefined && $("processedCount") !== "") {
    process += Number($("processedCount"));
  }
  globalChannelMap.put("totalProcess", process);

  var errorJson = globalChannelMap.get("errorJson");
  var errors = $("errors");

  if ($("errors")) {
    if (errorJson) {
      for (var errProp in errors) {
        if (errProp in errorJson) {
          var val = errors[errProp]["rows"];
          for (var i = 0; i < val.length; i++) {
            errorJson[errProp]["rows"].push(val[i]);
          }
        }
        else {
          // errors[globalErrMapProp] = {};
          errorJson[errProp] = errors[errProp];
        }
      }
    }
    else {
      errorJson = Object.assign({}, errorJson, errors);
    }


    globalChannelMap.put("errorJson", errorJson);
    globalChannelMap.put("errorJsonString", JSON.stringify(errorJson));
  }
} catch (err) {

  try {
    if (!dbConn) {
      dbConn = DatabaseConnectionFactory.createDatabaseConnection(
        jdbdcDriver,
        jbdcUrl,
        dbName,
        dbPassword
      );
    }
    //$('batch_id')/$('mcoId') resolve to "" (not null) when unset, which fails the ?::bigint cast below
    var mirthBatchId = $("batch_id") || null;
    var mirthMcoId = $("mcoId") || null;
    //Insert initial entries to the mco_record_details table with the batch_id we received from the previous call
    batch_details_insert = dbConn.executeCachedQuery(
      "insert into mco_data.mco_record_details(current_file_name, file_size_in_kb, total_records, created_on_utc, updated_on_utc, is_active, status, batch_id, reporting_month, tenant_id) VALUES (?, ?, ?, current_timestamp, current_timestamp, '1', 'MIRTH_INTERNAL_ERROR', ?::bigint, null, ?) returning batch_details_id",
      [$('originalFilename'), 0, 0, mirthBatchId, mirthMcoId]
    );
    var new_batch_details_id = batch_details_insert.next()
      ? batch_details_insert.getInt("batch_details_id")
      : null;
    var error_log_insert = dbConn.executeUpdate(
      "insert into mco_data.mco_record_error_logs (batch_id, error_json, created_on_utc, updated_on_utc, batch_details_id, is_active, error_type_id,tenant_id) values (?::bigint, ?::json, current_timestamp, current_timestamp, ?::bigint, '1', ?, ?)",
      [
        mirthBatchId,
        JSON.stringify(err),
        new_batch_details_id,
        errorTypes["MIRTH_INTERNAL_ERROR"]["error_type_id"],
        mirthMcoId,
      ]
    );
    throw err;
  } catch (err) {
    logger.info(err);
    throw err;
  } finally {
    globalChannelMap.clear();
    if ($('batchComplete') != true) {
      globalChannelMap.put("skipAllDestinations", true);
    }
    if (dbConn) {
      dbConn.close();
    }
  }
}

