properties.script:
importPackage(com.jcraft.jsch);
importPackage(java.io);
importPackage(java.lang);
importPackage(Packages.org.apache.commons.io);

//Get file util from java
var fileUtility = org.apache.commons.io.FileUtils();

//Get db creds
var jdbdcDriver = configurationMap.get("jdbdcDriver");
var jbdcUrl = configurationMap.get("jbdcUrl");
var dbName = configurationMap.get("dbName");
var dbPassword = configurationMap.get("dbPassword");

var originalFileName = $("originalFilename");
var dbOriginalFileName = "db_" + $("originalFilename");
var successFileName = "Success_" + $("originalFilename");
var errorFileName = "Error_" + $("originalFilename");

var thresholdValue = configurationMap.get("thresholdValue");
var totalRecords = $("recordsCount");
var errorRecords = $("totalErrors");
var errors = $("errorJson");

var thresholdExceeded;

if (thresholdExceecedFunction(thresholdValue, totalRecords, errorRecords)) {
	thresholdExceeded = true;
} else if (
	!thresholdExceecedFunction(thresholdValue, totalRecords, errorRecords) &&
	Object.keys(errors).length == 0
) {
	thresholdExceeded = false;
} else {
	thresholdExceeded = false;
}

function thresholdExceecedFunction(limit, totalRecords, errorRecords) {
	logger.info((totalRecords * limit) / 100 <= errorRecords);
	return (totalRecords * limit) / 100 <= errorRecords;
}

var username = configurationMap.get("sftpUserName");
var password = configurationMap.get("sftpPassword");
var ip = configurationMap.get("sftpIp");
var port = configurationMap.get("sftpPort");

var destinationUsername = configurationMap.get("destinationSftpUserName");
var destinationPassword = configurationMap.get("destinationSftpPassword");
var destinationIp = configurationMap.get("destinationSftpIp");
var destinationPort = configurationMap.get("destinationSftpPort");

//SMTP
var smtpHostname = configurationMap.get("smtpHostName");
var smtpPort = parseInt(configurationMap.get("smtpPort"));
var smtpUsername = configurationMap.get("smtpUsername");
var smtpPassword = configurationMap.get("smtpPassword");
var fromEmail = configurationMap.get("smtpFromEmail");

var batch_id = $("batch_id");
var batch_details_id = $("batch_details_id");

//Get error codes from configuration map
var errorCodesString = configurationMap.get("errorCodes");
//Since config map store it as string, parse it into json
var errorCodes = JSON.parse(errorCodesString);

var errorTypesString = configurationMap.get("errorTypes");
var errorTypes = JSON.parse(errorTypesString);

function sftpFileTransfer(
	destinationServerName,
	destinationPort,
	destinationUsername,
	destinationPassword,
	sourceFileName,
	destinationFileName,
	fileDestination,
	isSftp,
	isCopy
) {
	try {

		//Success Data/Error Data destinations write the file content to S3, not to local disk, so it is
		//pulled from the channelMap where those steps already staged it earlier in this same message
		//('validContent' / 'errorContent') instead of re-reading a local d:/mco-success, d:/mco-err file.
		var content = String(sourceFileName.indexOf("Error_") === 0 ? $('errorContent') : $('validContent'));
		logger.info("Streaming in-memory content for : " + sourceFileName);

		if (isSftp) {
			var fileToStream = new java.io.ByteArrayInputStream(java.lang.String(content).getBytes("UTF-8"));
			var jsch = new JSch();
			jsch.addIdentity("/lza-prod-esmf/internal/external-sftp/datalake-info/rochester-rhio-key-prod");
			var fileTransferred = false;
			var session2 = null;

			session2 = jsch.getSession(
				destinationUsername,
				destinationServerName,
				destinationPort
			);

			//      if (destinationPassword) {
			//      session2.setPassword(destinationPassword);
			//    }

			session2.setConfig("StrictHostKeyChecking", "no");

			session2.connect();
			// Create an SFTP channel
			var channel2 = session2.openChannel("sftp");
			channel2.connect();
			var sftp2 = channel2;

			var months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];

			var date = new Date();
			var month = date.getMonth(); // returns 0 - 11
			var date = date.getDate(); //Return today's date
			var year = new Date().getFullYear(); //Return the year

			var startDate = parseInt(configurationMap.get("startDate"))
			var endDate = parseInt(configurationMap.get("endDate"))


			if (startDate >= endDate) {
				if (date >= startDate) {
					if (month != 11) {
						month = month + 1;
					}
					else {
						month = 0;
						year = year + 1;
					}
				}
				else if (date <= endDate) {
					//Do nothing
				}
				else {
					// 	logger.info("Outside window period")
				}
			}

			var folderName = months[month] + '-' + year;

			logger.info(folderName);

			try {
				sftp2.stat(fileDestination + folderName + '/');
			} catch (err) {
				logger.info(err);
				logger.info("Failed stat")
				sftp2.mkdir(fileDestination + folderName + '/');
			}

			logger.info(
				"Dest : " + fileDestination + folderName + '/' + destinationFileName
			);
			sftp2.put(
				fileToStream,
				fileDestination + folderName + '/' + destinationFileName,
				sftp2.OVERWRITE
			);
			sftp2.stat(fileDestination + folderName + "/" + destinationFileName);
			channelMap.put("isFileSentToDL", true);
			logger.info("Transfer has been completed");

			return true; // Return true if the file was transferred successfully
		} else {
			org.apache.commons.io.FileUtils.writeStringToFile(
				java.io.File(fileDestination + destinationFileName),
				content,
				"UTF-8"
			);
			fileTransferred = true;
			return fileTransferred;
		}
	} catch (err) {
		logger.info("Failed sftp transfer file : " + sourceFileName);
		if (isSftp) {
			channelMap.put("isFileSentToDL", false);
		}

		throw err;
	}
	finally {
		if (fileToStream) {
			//Close the stream otherwise it will leak memory
			fileToStream.close();
		}
		if (sftp2) {
			// Disconnect and close the SFTP channel
			sftp2.disconnect();
		}
		if (session2) {
			// Disconnect and close the SSH session
			session2.disconnect();
		}
	}
}

