var jdbdcDriver = configurationMap.get("jdbdcDriver");
var jbdcUrl = configurationMap.get("jbdcUrl");
var dbName = configurationMap.get("dbName");
var dbPassword = configurationMap.get("dbPassword");

var thresholdValue = configurationMap.get("thresholdValue");
var totalRecords = recordsCount;
var errorRecords = totalErrors;
var status = $("fileStatus");
var errors = $("errorJson");
var isThreshold = false;

//SMTP
var smtpHostname = configurationMap.get("smtpHostName");
var smtpPort = parseInt(configurationMap.get("smtpPort"));
var smtpUsername = configurationMap.get("smtpUsername");
var smtpPassword = configurationMap.get("smtpPassword");
var fromEmail = configurationMap.get("smtpFromEmail");

//batch_id/$('batch_details_id') resolve to "" (not null) when unset, which fails downstream ? casts
var batch_id = batch_id ? parseInt(batch_id, 10) : null;
var batch_details_id = $("batch_details_id") ? parseInt($("batch_details_id"), 10) : null;
var mcoId = mcoId || null;
var totalProcess = totalProcess ? parseInt(totalProcess, 10) : 0;
var totalErrors = totalErrors ? parseInt(totalErrors, 10) : 0;
var recordsCount = recordsCount ? parseInt(recordsCount, 10) : 0;


logger.info("batch_id = [" + batch_id + "]");
logger.info("batch_details_id = [" + batch_details_id + "]");
logger.info("batch_id = [" + batch_id + "]");
logger.info("$('batch_details_id') = [" + $("batch_details_id") + "]");
logger.info("mcoId = [" + mcoId + "]");

var errorTypesString = configurationMap.get("errorTypes");
var errorTypes = JSON.parse(errorTypesString);


//Get error codes from configuration map
var errorCodesString = configurationMap.get("errorCodes");
//Since config map store it as string, parse it into json
var errorCodes = JSON.parse(errorCodesString);

try {
	var dbConn;

	try {
		if (thresholdExceeced(thresholdValue, totalRecords, errorRecords)) {
			status = "ERRORED";
			isThreshold = true;
			channelMap.put("thresholdExceed", isThreshold);
		} else if (
			!thresholdExceeced(thresholdValue, totalRecords, errorRecords) &&
			Object.keys(errors).length == 0
		) {
			status = "FULLY_PROCESSED";
		} else {
			status = "PARTIALLY_PROCESSED";
		}
		dbConn = DatabaseConnectionFactory.createDatabaseConnection(
			jdbdcDriver,
			jbdcUrl,
			dbName,
			dbPassword
		);
		if (!$("isResubmission")) {
			var batch_update = dbConn.executeUpdate(
				"update mco_data.mco_records set status = ?, qa_completed_time = current_timestamp,processed_count=?,errored_count=?,total_records=?,file_size_in_kb=?,updated_on_utc=current_timestamp where batch_id = ?",
				[
					status,
					totalProcess,
					totalErrors,
					recordsCount,
					$("totalFileSize"),
					batch_id,
				]
			);
		}

		var batch_details_update = dbConn.executeUpdate(
			"update mco_data.mco_record_details set status = ?, qa_completed_time = current_timestamp,processed_count=?,errored_count=?,total_records=?,file_size_in_kb=?,updated_on_utc=current_timestamp where batch_details_id = ?",
			[
				status,
				totalProcess,
				totalErrors,
				recordsCount,
				$("totalFileSize"),
				batch_details_id,
			]
		);

		if (totalErrors && totalErrors != 0) {
			var error_log_insert = dbConn.executeUpdate(
				"insert into mco_data.mco_record_error_logs (batch_id, error_json, created_on_utc, updated_on_utc, batch_details_id, is_active, error_type_id,tenant_id) values (?, ?::json, current_timestamp, current_timestamp, ?, '1', ?,?)",
				[
					batch_id,
					JSON.stringify($("errorJson")),
					batch_details_id,
					errorTypes["FIELD_VALIDATION_ERROR"]["error_type_id"],
					mcoId,
				]
			);
		}

		var last_error_count = dbConn.executeCachedQuery(
      "select errored_count from mco_data.mco_record_details where batch_details_id = ? and status != 'FILE_REJECTED' and is_active = '1' ",
			[batch_details_id]
		);
		while (last_error_count.next()) {
			error_count = last_error_count.getString(1);
		}

		if (status == 'ERRORED' && $("isResubmission")) {
			var batch_update = dbConn.executeUpdate(
        "update mco_data.mco_records set processed_count = ((select total_records from mco_data.mco_records where batch_id = ? and is_active = '1')-(select errored_count from mco_data.mco_record_details where batch_details_id = ? and is_active = '1')), errored_count = ?, qa_completed_time = current_timestamp where batch_id = ?",
				[
					batch_id,
					batch_details_id,
					totalErrors,
					batch_id,
				]
			);
		}
		else {
			var batch_update = dbConn.executeUpdate(
        "update mco_data.mco_records set status=?, processed_count = ((select total_records from mco_data.mco_records where batch_id = ? and is_active = '1' )-(select errored_count from mco_data.mco_record_details where batch_details_id = ? and is_active = '1')), errored_count = ?, qa_completed_time = current_timestamp where batch_id = ?",
				[
					status,
					batch_id,
					batch_details_id,
					totalErrors,
					batch_id,
				]
			);
		}

	} catch (err) {
		throw err;
	}
} catch (err) {

	try {
		if (!dbConn) {
			dbConn = DatabaseConnectionFactory.createDatabaseConnection(
				jdbdcDriver,
				jbdcUrl,
				dbName,
				dbPassword
			);
		}
		//Insert initial entries to the mco_record_details table with the batch_id we received from the previous call
		batch_details_insert = dbConn.executeCachedQuery(
			"insert into mco_data.mco_record_details(current_file_name, file_size_in_kb, total_records, created_on_utc, updated_on_utc, is_active, status, batch_id, reporting_month, tenant_id) VALUES (?, ?, ?, current_timestamp, current_timestamp, '1', 'MIRTH_INTERNAL_ERROR', ?, null, ?) returning batch_details_id",
			[$('originalFilename'), 0, 0, batch_id, mcoId]
		);
		var new_batch_details_id = batch_details_insert.next()
			? batch_details_insert.getInt("batch_details_id")
			: null;
		var error_log_insert = dbConn.executeUpdate(
			"insert into mco_data.mco_record_error_logs (batch_id, error_json, created_on_utc, updated_on_utc, batch_details_id, is_active, error_type_id, tenant_id) values (?, ?::json, current_timestamp, current_timestamp, ?, '1', ?,?)",
			[
				batch_id,
				JSON.stringify(err),
				new_batch_details_id,
				errorTypes["MIRTH_INTERNAL_ERROR"]["error_type_id"],
        mcoId,
			]
		);
		throw err;
	} catch (err) {
		logger.info(err);
		throw err;
	} finally {
		globalChannelMap.clear();
		if ($('batchComplete') != true) {
			globalChannelMap.put("skipAllDestinations", true);
		}
		if (dbConn) {
			dbConn.close();
		}
	}
}
finally {
	if (dbConn) {
		dbConn.close()
	}
}

function thresholdExceeced(limit, totalRecords, errorRecords) {
	logger.info((totalRecords * limit) / 100 <= errorRecords);
	return (totalRecords * limit) / 100 <= errorRecords;
}

