	var isResubmission = originalName.indexOf("RS_");
	var splittedFileName = originalName.split("_");;
	var rootFilename = "";
	if (isResubmission != -1) {
		//Remove first and last parts to remove RS_ and the _Newtimestamp
		for (var part = 1; part < splittedFileName.length - 1; part++) {
			if (part != splittedFileName.length - 2) {
				rootFilename = rootFilename + splittedFileName[part] + '_'
			}
			else {
				rootFilename = rootFilename + splittedFileName[part] + '.txt'
			}
		}
	}
	else {
		rootFilename = originalName
	}

	channelMap.put("successReceiptName", rootFilename);
	channelMap.put("successReceipt", file);
} catch (err) {
	try {
		if (!dbConn) {
			dbConn = DatabaseConnectionFactory.createDatabaseConnection(
				jdbdcDriver,
				jbdcUrl,
				dbName,
				dbPassword
			);
		}
		//$('batch_id')/$('mcoId') resolve to "" (not null) when unset, which fails the ?::bigint cast below
		var mirthBatchId = $("batch_id") || null;
		var mirthMcoId = $("mcoId") || null;
		//Insert initial entries to the mco_record_details table with the batch_id we received from the previous call
		batch_details_insert = dbConn.executeCachedQuery(
			"insert into mco_audit.mco_record_details(current_file_name, file_size_in_kb, total_records, created_on_utc, updated_on_utc, is_active, status, batch_id, reporting_month, mco_id) VALUES (?, ?, ?, current_timestamp, current_timestamp, '1', 'MIRTH_INTERNAL_ERROR', ?::bigint, null, ?::bigint) returning batch_details_id",
			[$('originalFilename'), 0, 0, mirthBatchId, mirthMcoId]
		);
		var new_batch_details_id = batch_details_insert.next()
			? batch_details_insert.getInt("batch_details_id")
			: null;
		var error_log_insert = dbConn.executeUpdate(
			"insert into mco_audit.mco_record_error_logs (batch_id, error_json, created_on_utc, updated_on_utc, batch_details_id, is_active, error_type_id) values (?::bigint, ?::json, current_timestamp, current_timestamp, ?::bigint, '1', ?)",
			[
				mirthBatchId,
				JSON.stringify(err),
				new_batch_details_id,
				errorTypes["MIRTH_INTERNAL_ERROR"]["error_type_id"],
			]
		);
		throw err;
	} catch (err) {
		logger.info(err);
		throw err;
	} finally {
		globalChannelMap.clear();
		if ($('batchComplete') != true) {
			globalChannelMap.put("skipAllDestinations", true);
		}
		if (dbConn) {
			dbConn.close();
		}
	}
} finally {
	if (dbConn) {
		dbConn.close();
	}
}

