var smtpPassword = configurationMap.get("smtpPassword");
var fromEmail = configurationMap.get("smtpFromEmail");

var emailList = JSON.parse(configurationMap.get("emailList"));
var isInternal = configurationMap.get("isTesting");

try {
	var months = [
		"January",
		"February",
		"March",
		"April",
		"May",
		"June",
		"July",
		"August",
		"September",
		"October",
		"November",
		"December",
	];

	var date = new Date();
	var month = date.getMonth(); // returns 0 - 11
	var date = date.getDate(); //Return today's date
	var year = new Date().getFullYear(); //Return the year

	var startDate = parseInt(configurationMap.get("startDate"))
	var endDate = parseInt(configurationMap.get("endDate"))

	if (startDate >= endDate) {
		if (date >= startDate) {
			if (month != 11) {
				month = month + 1;
			}
			else {
				month = 0;
				year = year + 1;
			}
		}
		else if (date <= endDate) {
			//Do nothing
		}
		else {
			// 	logger.info("Outside window period")
		}
	}

	var folderName = months[month] + "-" + year;
