			"\n\n\n" +
			"Please do not reply to this email. For any questions, reach out through the support channels or email us at support@grrhio.org";
	} else {
		subject = "GRRHIO Alert: Submitted Monthly ESMF File Rejected";
		body = $("mcoName") +
			": This is an automated notification that your submitted Monthly ESMF file " +
			$("originalFilename") +
			" has been rejected. A File Rejection response file with details of the rejection has been posted in the SFTP /esmf/outbound/error folder." +
			"\n\n\n" +
			"Please do not reply to this email. For any questions, reach out through the support channels or email us at support@grrhio.org";
	}

	var toEmails = "";
	var ccEmails = "";

	var mcoCode = $("mco_code");
	var emails;
  var excludeEmails = emailList["excludeEmailForRejection"];
  var ccEmailList = [];

	if (isInternal.equals("true")) {
		emails = emailList["internal"][mcoCode];
	} else {
		emails = emailList["external"][mcoCode];
	}
	if (emails) {
		toEmails = emails["to"].join(",");

    if (emails["cc"]) {
      for (var i = 0; i < emails["cc"].length; i++) {
        var ccEmailId = emails["cc"][i];
        if (excludeEmails) {
          if (!excludeEmails.includes(ccEmailId)) {
            ccEmailList.push(ccEmailId);
          }
        }
      }
    }

    ccEmails = ccEmailList.join(",");
	}


	var smtpConn = SMTPConnection(smtpHostname, smtpPort, 0, true, "TLS", smtpUsername, smtpPassword, fromEmail);
	smtpConn.send(toEmails, ccEmails, fromEmail, subject, body, "UTF-8");
} catch (err) {
