		var new_batch_details_id = batch_details_insert.next()
			? batch_details_insert.getInt("batch_details_id")
			: null;
		var error_log_insert = dbConn.executeUpdate(
			"insert into mco_data.mco_record_error_logs (batch_id, error_json, created_on_utc, updated_on_utc, batch_details_id, is_active, error_type_id, tenant_id) values (?::bigint, ?::json, current_timestamp, current_timestamp, ?::bigint, '1', ?, ?)",
			[
