properties.script:
var jdbdcDriver = configurationMap.get("jdbdcDriver");
var jbdcUrl = configurationMap.get("jbdcUrl");
var dbName = configurationMap.get("dbName");
var dbPassword = configurationMap.get("dbPassword");
var dbConn;

//SMTP
var smtpHostname = configurationMap.get("smtpHostName");
var smtpPort = parseInt(configurationMap.get("smtpPort"));
var smtpUsername = configurationMap.get("smtpUsername");
var smtpPassword = configurationMap.get("smtpPassword");
var fromEmail = configurationMap.get("smtpFromEmail");
var toAlertEmails = configurationMap.get("alertEmails");

var mco_id = $("mcoId");
var batch_select;
var batch_details_insert;
var batch_id;
var batch_details_id;
var fileName = $("originalFilename");
var errorJson = {};
var rejectionReason = globalChannelMap.get("invalidFileReason");

//Get error codes from configuration map
var errorCodesString = configurationMap.get("errorCodes");
//Since config map store it as string, parse it into json
var errorCodes = JSON.parse(errorCodesString);

var errorTypesString = configurationMap.get("errorTypes");
var errorTypes = JSON.parse(errorTypesString);

var destinationFileName = $("destinationFileName");

var isResubmission = fileName.indexOf("RS_");
var splittedFileName = fileName.split("_");
var isFileRejected = fileName
  .toLowerCase()
  .indexOf("FileRejected_".toLowerCase());

if (isFileRejected != -1) {
  splittedFileName = fileName.split("_").slice(1);
  fileName = fileName.split("_").slice(1).join("_");
}

var batchDetailsFileName = "";
var rootFilename = "";

if (isResubmission != -1) {
  //Remove first and last parts to remove RS_ and the _Newtimestamp
  for (var part = 1; part < splittedFileName.length - 1; part++) {
    //If we are not at last part, add _ to rebuild the file name
    if (part != splittedFileName.length - 2) {
      rootFilename = rootFilename + splittedFileName[part] + "_";
    }
    //If we are at last part, add .txt to indicate the format
    else {
      rootFilename = rootFilename + splittedFileName[part] + ".txt";
    }
  }
}
//If it's not a resubmission, use the original file name to call the DB
else {
  rootFilename = fileName;
}
rootFilename = rootFilename.toString();

if (
  destinationFileName.toLowerCase().indexOf("FileRejected".toLowerCase()) != -1
) {
  channelMap.put("destinationFileName", rootFilename);
}

if (rejectionReason) {
  for (var i = 0; i < rejectionReason.length; i++) {
    var code = errorCodes[rejectionReason[i]]["code"];
    errorJson[code] = {};
    errorJson[code]["rows"] = [1];
    errorJson[code]["description"] =
      errorCodes[rejectionReason[i]]["description"];
  }
}

try {
  dbConn = DatabaseConnectionFactory.createDatabaseConnection(
    jdbdcDriver,
    jbdcUrl,
    dbName,
    dbPassword
  );

  //Insert initial entries to the mco_records table
  batch_select = dbConn.executeCachedQuery(
    "select batch_id, resubmitted_count, status, total_records from mco_data.mco_records where root_file_name = ? and is_active = '1' ",
    [rootFilename]
  );
  batch_id = batch_select.next() ? batch_select.getInt("batch_id") : null;
  if ("EC084" in errorJson) {
    //Insert initial entries to the mco_record_details table with the batch_id we received from the previous call
    batch_details_insert = dbConn.executeCachedQuery(
      "insert into mco_data.mco_record_details(current_file_name, file_size_in_kb, total_records, created_on_utc, updated_on_utc, is_active, status, batch_id, reporting_month, tenant_id) VALUES (?, ?, ?, current_timestamp, current_timestamp, '1', 'LAMBDA_INTERNAL_ERROR', ?::bigint, null, ?) returning batch_details_id",
      [fileName, 0, 0, batch_id, mco_id]
    );
    batch_details_id = batch_details_insert.next()
      ? batch_details_insert.getInt("batch_details_id")
      : null;
  } else {
    if ("EC085" in errorJson) {
      logger.info("EC085 in error json");
      batch_details_insert = dbConn.executeCachedQuery(
        "select batch_details_id from mco_data.mco_record_details where batch_id = ?::bigint and is_active = '1' ORDER BY batch_details_id DESC LIMIT 1",
        [batch_id]
      );
      batch_details_id = batch_details_insert.next()
        ? batch_details_insert.getInt("batch_details_id")
        : null;
      batch_details_deactivate = dbConn.executeUpdate(
        "update mco_data.mco_record_details set status='FILE_REJECTED' where batch_details_id = ?::bigint",
        [batch_details_id]
      );
      logger.info("updated status");
    }
    else if ("EC088" in errorJson) {
      logger.info("EC088 in error json");

      var batchUpdate = dbConn.executeUpdate("update mco_data.mco_records set status='FILE_REJECTED' where batch_id = ?::bigint", [batch_id])

