*/
function getCOVIDConn()
{
	var getCOVIDConn = globalMap.get("getCOVIDConn" + channelId);
	if (getCOVIDConn != null)
	{
		try { getCOVIDConn.executeCachedQuery("select 1 as test_result;"); }
		catch(ex) { getCOVIDConn = null; }
	}
	if (getCOVIDConn == null)
	{
		try
		{
			getCOVIDConn = DatabaseConnectionFactory.createDatabaseConnection("org.postgresql.Driver",
				"jdbc:postgresql://localhost:5432/covid_registry", "covid_registry", "IeD9ohdol@ee");
			getCOVIDConn.executeCachedQuery("select 1 as test_result;");
		}
		catch(ex) { getCOVIDConn = null; }
		globalMap.put("getCOVIDConn" + channelId, getCOVIDConn);
	}
	return getCOVIDConn;
}
